        const totalApps = grandTotal.totalApplications;
        const qdTheory = totalApps * FEE_RATES.theory;
        const qdSim = totalApps * FEE_RATES.simulation;
        const qdField = totalApps * FEE_RATES.practicalCourse;
        const qdRoad = totalApps * FEE_RATES.onRoad;
        const qdTotal = qdTheory + qdSim + qdField + qdRoad;

        // II. Phí sát hạch thực tế thí sinh tham dự (Tính trên số lượng thực tế dự thi từng phần)
