        const realSim = grandTotal.simulation.total * FEE_RATES.simulation;
        const realField = grandTotal.practicalCourse.total * FEE_RATES.practicalCourse;
        const realRoad = grandTotal.onRoad.total * FEE_RATES.onRoad;
