    ]);

    rows.push([
        "", "TỔNG CỘNG", "", 
        totals.applications, 
        totals.theory, 
        totals.simulation, 
        totals.practical, 
        totals.road
    ]);

    const ws = XLSX.utils.aoa_to_sheet([[title], [], headers, ...rows]);
