                                            <div className="bg-white dark:bg-gray-800 p-2 rounded border dark:border-gray-700 text-xs">
                                                <div className="text-gray-400 uppercase text-[9px] mb-1">MP</div>
                                                <div className="font-bold">{getStudentVal(attempt.data, ['MÔ PHỎNG']) || '-'}</div>
                                            </div>
                                            <div className="bg-white dark:bg-gray-800 p-2 rounded border dark:border-gray-700 text-xs">
                                                <div className="text-gray-400 uppercase text-[9px] mb-1">SH</div>
                                                <div className="font-bold">{getStudentVal(attempt.data, ['SA HÌNH']) || '-'}</div>
                                            </div>
                                            <div className="bg-white dark:bg-gray-800 p-2 rounded border dark:border-gray-700 text-xs">
                                                <div className="text-gray-400 uppercase text-[9px] mb-1">ĐT</div>
                                                <div className="font-bold">{getStudentVal(attempt.data, ['ĐƯỜNG TRƯỜNG']) || '-'}</div>
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import type { AppData, LicenseClassData, StudentRecord } from '../types';
import { getResultStatus, isStudentAbsent, isStudentPassed } from './reportUtils';

// Hàm helper xử lý ngày tháng phức tạp từ Excel
export const parseDateValue = (val: any): string => {
    if (!val) return '';

    // 1. Nếu là số (Excel Serial Date)
    if (typeof val === 'number') {
        const date = new Date(Math.round((val - 25569) * 86400 * 1000));
        return date.toISOString().split('T')[0];
    }

    const str = String(val).trim();
    if (!str) return '';

    // 2. Nếu là định dạng dd/mm/yyyy hoặc dd-mm-yyyy
    const dmyRegex = /^(\d{1,2})[/-](\d{1,2})[/-](\d{4})$/;
    const match = str.match(dmyRegex);
    if (match) {
        const [_, d, m, y] = match;
        return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
    }

    // 3. Thử parse mặc định
    const parsed = new Date(str);
    if (!isNaN(parsed.getTime())) {
        return parsed.toISOString().split('T')[0];
    }

    return str;
};

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};
    const keyMap: {[key: string]: string} = {
        'SỐ BÁO DANH': 'SỐ BÁO DANH', 'SBD': 'SỐ BÁO DANH', 'SO BAO DANH': 'SỐ BÁO DANH', 'SỐ BD': 'SỐ BÁO DANH',
        'MÃ HỌC VIÊN': 'MÃ HỌC VIÊN', 'MÃ HV': 'MÃ HỌC VIÊN', 'MAHV': 'MÃ HỌC VIÊN', 'MADK': 'MÃ HỌC VIÊN', 'MÃ ĐK': 'MÃ HỌC VIÊN', 'MÃ SỐ': 'MÃ HỌC VIÊN', 'MA SO': 'MÃ HỌC VIÊN',
        'HỌ VÀ TÊN': 'HỌ VÀ TÊN', 'HO VA TEN': 'HỌ VÀ TÊN', 'HỌ TÊN': 'HỌ TÊN', 'TÊN': 'HỌ VÀ TÊN', 'TEN HOC VIEN': 'HỌ VÀ TÊN',
        'HẠNG GPLX': 'HẠNG GPLX', 'HẠNG': 'HẠNG GPLX', 'HANG': 'HẠNG GPLX', 'HANG XE': 'HẠNG GPLX', 'HẠNG ĐĂNG KÝ': 'HẠNG GPLX',
        'NỘI DUNG THI': 'NỘI DUNG THI', 'ND THI': 'NỘI DUNG THI', 'NDSH': 'NỘI DUNG THI', 'NỘI DUNG': 'NỘI DUNG THI',
        'LÝ THUYẾT': 'LÝ THUYẾT', 'LT': 'LÝ THUYẾT', 'LY THUYET': 'LÝ THUYẾT', 'ĐIỂM LT': 'LÝ THUYẾT', 'KQ LT': 'LÝ THUYẾT',
        'MÔ PHỎNG': 'MÔ PHỎNG', 'MP': 'MÔ PHỎNG', 'MO PHONG': 'MÔ PHỎNG', 'ĐIỂM MP': 'MÔ PHỎNG', 'KQ MP': 'MÔ PHỎNG',
        'SA HÌNH': 'SA HÌNH', 'SH': 'SA HÌNH', 'SA HINH': 'SA HÌNH', 'TH TRONG HÌNH': 'SA HÌNH', 'KQ SH': 'SA HÌNH',
        'ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'ĐT': 'ĐƯỜNG TRƯỜNG', 'DT': 'ĐƯỜNG TRƯỜNG', 'KQ ĐT': 'ĐƯỜNG TRƯỜNG', 'TH ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG',
        'SỐ CHỨNG MINH': 'SỐ CHỨNG MINH', 'CCCD': 'SỐ CHỨNG MINH', 'CMND': 'SỐ CHỨNG MINH', 'SỐ THẺ': 'SỐ CHỨNG MINH',
        'NGÀY SINH': 'NGÀY SINH', 'NGAY SINH': 'NGÀY SINH', 'NS': 'NGÀY SINH',
        'NGÀY THI': 'NGÀY THI', 'NGAY THI': 'NGÀY THI', 'NGÀY SÁT HẠCH': 'NGÀY THI', 'NGAY SH': 'NGÀY THI', 'DATE': 'NGÀY THI',
        'NƠI CƯ TRÚ': 'NƠI CƯ TRÚ', 'DIA CHI': 'NƠI CƯ TRÚ', 'HỘ KHẨU': 'NƠI CƯ TRÚ', 'TRÚ QUÁN': 'NƠI CƯ TRÚ'
    };

    Object.keys(record).forEach(key => {
        const cleanKey = key.trim().toUpperCase().replace(/\s+/g, ' ');
        const mapped = keyMap[cleanKey] || cleanKey;
        normalized[mapped] = record[key];
    });

    // Chuẩn hóa các giá trị ngày tháng ngay trong quá trình normalize
    if (normalized['NGÀY SINH']) normalized['NGÀY SINH'] = parseDateValue(normalized['NGÀY SINH']);
    if (normalized['NGÀY THI']) normalized['NGÀY THI'] = parseDateValue(normalized['NGÀY THI']);

    if (!normalized['NỘI DUNG THI']) {
        const parts = [];
        if (normalized['LÝ THUYẾT'] !== undefined && normalized['LÝ THUYẾT'] !== '') parts.push('L');
        if (normalized['MÔ PHỎNG'] !== undefined && normalized['MÔ PHỎNG'] !== '') parts.push('M');
        if (normalized['SA HÌNH'] !== undefined && normalized['SA HÌNH'] !== '') parts.push('H');
        if (normalized['ĐƯỜNG TRƯỜNG'] !== undefined && normalized['ĐƯỜNG TRƯỜNG'] !== '') parts.push('Đ');
        normalized['NỘI DUNG THI'] = parts.join('+');
    }

    return normalized as StudentRecord;
};

const createEmptyClass = (className: string): LicenseClassData => ({
    class: className,
    totalApplications: 0,
    totalParticipants: 0,
    theory: { total: 0, pass: 0, fail: 0 },
    simulation: { total: 0, pass: 0, fail: 0 },
    practicalCourse: { total: 0, pass: 0, fail: 0 },
    onRoad: { total: 0, pass: 0, fail: 0 },
    finalPass: 0,
});

export const normalizeData = (raw: any[]): StudentRecord[] => raw.map(normalizeRecord);

export const processExcelData = (rawRecords: StudentRecord[]): AppData => {
    const firstTime: Record<string, LicenseClassData> = {};
    const retake: Record<string, LicenseClassData> = {};

    rawRecords.forEach(record => {
        const className = String(record['HẠNG GPLX'] || '').trim();
        if (!className) return;

        const maHV = String(record['MÃ HỌC VIÊN'] || '').trim();
        const isRetake = maHV.startsWith('2721') || maHV.startsWith('2722') || maHV.startsWith('2411');
        const target = isRetake ? retake : firstTime;

        if (!target[className]) target[className] = createEmptyClass(className);
        const data = target[className];

        data.totalApplications++;
        if (!isStudentAbsent(record)) data.totalParticipants++;

        const noiDung = String(record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');

        if (noiDung.includes('L')) {
            const status = getResultStatus(record['LÝ THUYẾT']);
            if (status.participated) {
                data.theory.total++;
                if (status.passed) data.theory.pass++;
            }
        }
        if (noiDung.includes('M')) {
            const status = getResultStatus(record['MÔ PHỎNG']);
            if (status.participated) {
                data.simulation.total++;
                if (status.passed) data.simulation.pass++;
            }
        }
        if (noiDung.includes('H')) {
            const status = getResultStatus(record['SA HÌNH']);
            if (status.participated) {
                data.practicalCourse.total++;
                if (status.passed) data.practicalCourse.pass++;
            }
        }
        if (noiDung.includes('D')) {
            const status = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
            if (status.participated) {
                data.onRoad.total++;
                if (status.passed) data.onRoad.pass++;
            }
        }
        if (isStudentPassed(record)) data.finalPass++;
    });

    const finalize = (obj: Record<string, LicenseClassData>) => 
        Object.values(obj)
            .map(v => ({
                ...v,
                theory: { ...v.theory, fail: Math.max(0, v.theory.total - v.theory.pass) },
                simulation: { ...v.simulation, fail: Math.max(0, v.simulation.total - v.simulation.pass) },
                practicalCourse: { ...v.practicalCourse, fail: Math.max(0, v.practicalCourse.total - v.practicalCourse.pass) },
                onRoad: { ...v.onRoad, fail: Math.max(0, v.onRoad.total - v.onRoad.pass) }
            }))
            .sort((a, b) => a.class.localeCompare(b.class));

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: finalize(firstTime) },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: finalize(retake) }
    };
};

import React, { useState, useMemo, useRef } from 'react';
import type { SavedSession, StudentRecord, LicenseClassData } from '../../types';
import { storageService } from '../../services/storageService';
import { isStudentPassed, isStudentAbsent } from '../../services/reportUtils';
import { normalizeData, processExcelData } from '../../services/excelProcessor';

declare const XLSX: any;

interface StudentProfile {
    studentId: string;
    studentName: string;
    cccd: string;
    licenseClass: string;
    attempts: {
        sessionName: string;
        reportDate: string;
        data: StudentRecord;
    }[];
    otherIdsWithSameCCCD: string[];
}

interface StudentLookupPageProps {
    sessions: SavedSession[];
    isLoading: boolean;
    onRefresh: () => void;
}

const getStudentVal = (s: any, keys: string[]) => {
    if (!s) return '';
    const objKeys = Object.keys(s);
    for (const targetKey of keys) {
        const foundKey = objKeys.find(k => k.trim().toUpperCase() === targetKey.toUpperCase());
        if (foundKey && s[foundKey] !== undefined && s[foundKey] !== null) {
            return String(s[foundKey]).trim();
        }
    }
    return '';
};

const removeAccents = (str: string) => {
    return str.normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/đ/g, 'd').replace(/Đ/g, 'D');
};

export const StudentLookupPage: React.FC<StudentLookupPageProps> = ({ sessions, isLoading, onRefresh }) => {
    const [selectedStudent, setSelectedStudent] = useState<StudentProfile | null>(null);
    const [isImporting, setIsImporting] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [searchTerm, setSearchTerm] = useState('');
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [selectedClass, setSelectedClass] = useState('all');
    const [selectedStatus, setSelectedStatus] = useState<'all' | 'passed' | 'failed' | 'absent'>('all');

    const uniqueClasses = useMemo(() => {
        const classes = new Set<string>();
        sessions.forEach(s => {
            s.studentRecords?.forEach(r => {
                const cls = getStudentVal(r, ['HẠNG GPLX', 'HẠNG']);
                if (cls) classes.add(cls);
            });
        });
        return Array.from(classes).sort();
    }, [sessions]);

    const downloadHistorySample = () => {
        const sampleData = [
            { 
                'SBD': '101', 
                'MÃ HỌC VIÊN': '27210001', 
                'HỌ VÀ TÊN': 'Nguyễn Văn Mẫu Lịch Sử', 
                'SỐ CHỨNG MINH': '037190001234',
                'NGÀY SINH': '15/05/1990',
                'NGÀY THI': '28/10/2024',
                'HẠNG GPLX': 'B2', 
                'NỘI DUNG THI': 'L+M+H+Đ',
                'LÝ THUYẾT': 'ĐẠT', 
                'MÔ PHỎNG': 'ĐẠT', 
                'SA HÌNH': 'ĐẠT', 
                'ĐƯỜNG TRƯỜNG': 'ĐẠT'
            },
            { 
                'SBD': '102', 
                'MÃ HỌC VIÊN': '27225588', 
                'HỌ VÀ TÊN': 'Trần Thị Dữ Liệu Cũ', 
                'SỐ CHỨNG MINH': '037190005678',
                'NGÀY SINH': '20/10/1995',
                'NGÀY THI': '15/09/2024',
                'HẠNG GPLX': 'C', 
                'NỘI DUNG THI': 'L+M+H+Đ',
                'LÝ THUYẾT': 'ĐẠT', 
                'MÔ PHỎNG': 'ĐẠT', 
                'SA HÌNH': 'KHÔNG ĐẠT', 
                'ĐƯỜNG TRƯỜNG': ''
            }
        ];
        const worksheet = XLSX.utils.json_to_sheet(sampleData);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "LichSuThi");
        XLSX.writeFile(workbook, "Mau_Nap_Du_Lieu_Lich_Su.xlsx");
    };

    const handleImportHistory = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setIsImporting(true);
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onload = async (event) => {
                try {
                    const dataArr = new Uint8Array(event.target!.result as ArrayBuffer);
                    const workbook = XLSX.read(dataArr, { type: 'array' });
                    const worksheet = workbook.Sheets[workbook.SheetNames[0]];
                    const json: any[] = XLSX.utils.sheet_to_json(worksheet);

                    // 1. Chuẩn hóa dữ liệu ngay lập tức (Xử lý các loại định dạng ngày Excel)
                    const cleanRecords = normalizeData(json);

                    // 2. Gom nhóm hồ sơ theo Ngày thi
                    const groups: Record<string, StudentRecord[]> = {};
                    cleanRecords.forEach(r => {
                        const dateStr = r['NGÀY THI'] || r['NGÀY SINH'] || '2025-01-01';
                        const key = `Imported_${dateStr}`;
                        if (!groups[key]) groups[key] = [];
                        groups[key].push(r);
                    });

                    // 3. Tạo các Session tương ứng
                    const newSessions: SavedSession[] = Object.entries(groups).map(([key, records]) => {
                        const appData = processExcelData(records);
                        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
                        const gt: LicenseClassData = allRows.reduce((acc, row) => {
                            acc.totalApplications += row.totalApplications;
                            acc.totalParticipants += row.totalParticipants;
                            acc.finalPass += row.finalPass;
                            return acc;
                        }, { class: 'a+b', totalApplications: 0, totalParticipants: 0, theory: {total:0,pass:0,fail:0}, simulation: {total:0,pass:0,fail:0}, practicalCourse: {total:0,pass:0,fail:0}, onRoad: {total:0,pass:0,fail:0}, finalPass: 0 });

                        const actualDateStr = key.replace('Imported_', '');
                        let reportDateISO = new Date().toISOString();
                        try {
                            const parsed = new Date(actualDateStr);
                            if (!isNaN(parsed.getTime())) reportDateISO = parsed.toISOString();
                        } catch (e) {}

                        return {
                            id: `hist-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
                            name: `Dữ liệu nạp từ file Excel ngày ${actualDateStr}`,
                            createdAt: Date.now(),
                            reportDate: reportDateISO,
                            studentRecords: records,
                            appData,
                            grandTotal: gt,
                            reportMetadata: { meetingTime: '', meetingLocation: '', organizer: '', attendees: [] },
                            trainingUnits: []
                        };
                    });

                    if (newSessions.length === 0) throw new Error("Không tìm thấy dữ liệu hợp lệ trong file.");

                    await storageService.bulkSaveSessions(newSessions);
                    alert(`Thành công! Đã nạp ${cleanRecords.length} hồ sơ, phân vào ${newSessions.length} kỳ thi dựa trên ngày tháng.`);
                    onRefresh();
                } catch (err) {
                    alert("Lỗi nạp dữ liệu: " + (err as Error).message);
                } finally {
                    setIsImporting(false);
                    if (fileInputRef.current) fileInputRef.current.value = '';
                }
            };
            reader.readAsArrayBuffer(file);
        }
    };

    const searchResults = useMemo(() => {
        if (!sessions || sessions.length === 0) return [];
        const studentMap = new Map<string, StudentProfile>();
        const cccdToIdsMap = new Map<string, Set<string>>();
        const term = removeAccents(searchTerm.toLowerCase().trim());
        const fromDateStr = dateFrom ? new Date(dateFrom).getTime() : 0;
        const toDateStr = dateTo ? new Date(dateTo).getTime() + 86399999 : Infinity;

        sessions.forEach(session => {
            session.studentRecords?.forEach(student => {
                const sid = getStudentVal(student, ['MÃ HỌC VIÊN', 'MAHV', 'MADK']);
                const cccd = getStudentVal(student, ['SỐ CHỨNG MINH', 'CCCD', 'CMND']);
                if (cccd && sid) {
                    if (!cccdToIdsMap.has(cccd)) cccdToIdsMap.set(cccd, new Set());
                    cccdToIdsMap.get(cccd)!.add(sid);
                }
            });
        });

        sessions.forEach(session => {
            const sessionTime = new Date(session.reportDate).getTime();
            if (sessionTime < fromDateStr || sessionTime > toDateStr) return;

            session.studentRecords?.forEach(student => {
                const sid = getStudentVal(student, ['MÃ HỌC VIÊN', 'MAHV']);
                if (!sid) return;

                const sClass = getStudentVal(student, ['HẠNG GPLX', 'HẠNG']);
                if (selectedClass !== 'all' && sClass !== selectedClass) return;

                const isPass = isStudentPassed(student);
                const isAbs = isStudentAbsent(student);
                if (selectedStatus === 'passed' && !isPass) return;
                if (selectedStatus === 'absent' && !isAbs) return;
                if (selectedStatus === 'failed' && (isPass || isAbs)) return;

                const nameRaw = getStudentVal(student, ['HỌ VÀ TÊN', 'HOTEN']);
                const name = removeAccents(nameRaw.toLowerCase());
                const cccd = getStudentVal(student, ['SỐ CHỨNG MINH', 'CCCD']).toLowerCase();
                const sbd = getStudentVal(student, ['SỐ BÁO DANH', 'SBD']).toLowerCase();

                if (term && !name.includes(term) && !sid.toLowerCase().includes(term) && !cccd.includes(term) && !sbd.includes(term)) return;

                if (!studentMap.has(sid)) {
                    const studentCccd = getStudentVal(student, ['SỐ CHỨNG MINH', 'CCCD']);
                    studentMap.set(sid, {
                        studentId: sid,
                        studentName: nameRaw,
                        cccd: studentCccd,
                        licenseClass: sClass,
                        attempts: [],
